// ─── Test Report Logger ───────────────────────────────────────
type TestResult = { name: string; status: 'PASS' | 'FAIL'; error?: string };
const results: TestResult[] = [];

function logResult(name: string, pass: boolean, err?: any) {
  results.push({ name, status: pass ? 'PASS' : 'FAIL', error: err?.message ?? String(err ?? '') });
}

afterAll(() => {
  const passed = results.filter((r) => r.status === 'PASS').length;
  const failed = results.filter((r) => r.status === 'FAIL').length;
  console.log('\n══════════════════════════════════════════════════════');
  console.log('  AURA HEALTH — TEST REPORT');
  console.log('══════════════════════════════════════════════════════');
  results.forEach((r) => {
    const mark = r.status === 'PASS' ? '✓' : '✗';
    const line = `  ${mark}  ${r.name}`;
    if (r.status === 'FAIL') console.error(line + `\n      → ${r.error}`);
    else console.log(line);
  });
  console.log('──────────────────────────────────────────────────────');
  console.log(`  PASSED: ${passed}  |  FAILED: ${failed}  |  TOTAL: ${results.length}`);
  console.log('══════════════════════════════════════════════════════\n');
});

