// 5. BUSINESS LOGIC — onboarding BMI calculation
// ══════════════════════════════════════════════════════════════

describe('onboarding — BMI calculation logic', () => {

  function calcBMI(weightKg: number, heightCm: number): number | null {
    if (!weightKg || !heightCm || weightKg <= 0 || heightCm <= 0) return null;
    const h = heightCm / 100;
    return Math.round((weightKg / (h * h)) * 100) / 100;
  }

  test('calcBMI: known value 70kg / 175cm = 22.86', () => {
    try {
      const bmi = calcBMI(70, 175);
      expect(bmi).toBeCloseTo(22.86, 1);
      logResult('calcBMI: 70kg/175cm ≈ 22.86', true);
    } catch (e) { logResult('calcBMI: 70kg/175cm ≈ 22.86', false, e); throw e; }
  });

  test('calcBMI: returns null for zero/negative inputs', () => {
    try {
      expect(calcBMI(0, 175)).toBeNull();
      expect(calcBMI(70, 0)).toBeNull();
      expect(calcBMI(-5, 175)).toBeNull();
      logResult('calcBMI: null for invalid inputs', true);
    } catch (e) { logResult('calcBMI: null for invalid inputs', false, e); throw e; }
  });

  test('BMI categories cover full range', () => {
    try {
      type BmiCat = { label: string; color: string; comment: string };
      function bmiCategory(bmi: number | null): BmiCat | null {
        if (bmi === null) return null;
        if (bmi < 18.5) return { label: 'Underweight', color: '#3B82F6', comment: '...' };
        if (bmi < 25)   return { label: 'Normal',      color: '#10B981', comment: '...' };
        if (bmi < 30)   return { label: 'Overweight',  color: '#F59E0B', comment: '...' };
        if (bmi < 35)   return { label: 'Obese (Class I)', color: '#F97316', comment: '...' };
        return           { label: 'Obese (Class II+)', color: '#EF4444', comment: '...' };
      }
      expect(bmiCategory(17)?.label).toBe('Underweight');
      expect(bmiCategory(22)?.label).toBe('Normal');
      expect(bmiCategory(27)?.label).toBe('Overweight');
      expect(bmiCategory(32)?.label).toBe('Obese (Class I)');
      expect(bmiCategory(40)?.label).toBe('Obese (Class II+)');
      expect(bmiCategory(null)).toBeNull();
      logResult('BMI categories: all 5 ranges correct', true);
    } catch (e) { logResult('BMI categories: all 5 ranges correct', false, e); throw e; }
  });
});

// ══════════════════════════════════════════════════════════════
// 6. LOGIC — Novra Score calculation (isolated)
// ══════════════════════════════════════════════════════════════

describe('Novra Score — isolated calculation logic', () => {

  function calcScore(
    calPct: number,     // 0-1
    selectedType: string | null,
    moodRating: number, // 1-5, 0 = not rated
    sleepPct: number,   // 0-1
  ) {
    const foodScore  = Math.min(Math.round(calPct * 25), 25);
    const moveScore  = selectedType === 'rest' ? 10 : selectedType ? 25 : 0;
    const moodScore  = moodRating > 0 ? Math.round(moodRating * 5) : 0;
    const sleepScore = sleepPct > 0 ? Math.min(Math.round(sleepPct * 25), 25) : 0;
    return Math.min(foodScore + moveScore + moodScore + sleepScore, 100);
  }

  test('perfect day = 100 score', () => {
    try {
      const score = calcScore(1.0, 'chest', 5, 1.0);
      // food=25, move=25, mood=25, sleep=25 → 100
      expect(score).toBe(100);
      logResult('Novra Score: perfect day = 100', true);
    } catch (e) { logResult('Novra Score: perfect day = 100', false, e); throw e; }
  });

  test('zero day = 0 score', () => {
    try {
      const score = calcScore(0, null, 0, 0);
      expect(score).toBe(0);
      logResult('Novra Score: empty day = 0', true);
    } catch (e) { logResult('Novra Score: empty day = 0', false, e); throw e; }
  });

  test('rest day gives 10 move points (not 0 or 25)', () => {
    try {
      const score = calcScore(0, 'rest', 0, 0);
      expect(score).toBe(10);
      logResult('Novra Score: rest day = 10 move points', true);
    } catch (e) { logResult('Novra Score: rest day = 10 move points', false, e); throw e; }
  });

  test('score is capped at 100', () => {
    try {
      // Even with all maxed, should not exceed 100
      const score = calcScore(2.0, 'chest', 5, 2.0);
      expect(score).toBeLessThanOrEqual(100);
      logResult('Novra Score: capped at 100', true);
    } catch (e) { logResult('Novra Score: capped at 100', false, e); throw e; }
  });

  test('calorie overcount doesnt boost food score beyond 25', () => {
    try {
      const foodScore = Math.min(Math.round(2.0 * 25), 25);
      expect(foodScore).toBe(25);
      logResult('Novra Score: foodScore capped at 25', true);
    } catch (e) { logResult('Novra Score: foodScore capped at 25', false, e); throw e; }
  });
});

