// 7. SECURITY — JWT shape validation
// ══════════════════════════════════════════════════════════════

describe('_layout.tsx — isJWTShaped() security validation', () => {

  function isJWTShaped(token: string): boolean {
    const parts = token.split('.');
    return parts.length === 3 && parts.every((p) => /^[A-Za-z0-9_=+-]+$/.test(p));
  }

  test('valid JWT shape passes', () => {
    try {
      const validJWT = 'eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiJ1c2VyMTIzIn0.SflKxwRJSMeKKF2QT4fwpMeJf36P';
      expect(isJWTShaped(validJWT)).toBe(true);
      logResult('isJWTShaped: valid JWT → true', true);
    } catch (e) { logResult('isJWTShaped: valid JWT → true', false, e); throw e; }
  });

  test('non-JWT strings are rejected', () => {
    try {
      expect(isJWTShaped('')).toBe(false);
      expect(isJWTShaped('just.two')).toBe(false);
      expect(isJWTShaped('one')).toBe(false);
      expect(isJWTShaped('a.b.c.d')).toBe(false); // 4 parts
      logResult('isJWTShaped: malformed tokens rejected', true);
    } catch (e) { logResult('isJWTShaped: malformed tokens rejected', false, e); throw e; }
  });

  test('tokens with dangerous characters are rejected', () => {
    try {
      expect(isJWTShaped('a<script>.b.c')).toBe(false);
      expect(isJWTShaped('a.b.c; DROP TABLE')).toBe(false);
      expect(isJWTShaped('../../../etc.b.c')).toBe(false);
      logResult('isJWTShaped: XSS / injection tokens rejected', true);
    } catch (e) { logResult('isJWTShaped: XSS / injection tokens rejected', false, e); throw e; }
  });

  test('only-our-scheme URLs pass deep link filter', () => {
    try {
      const APP_SCHEME = 'novra-health://';
      const isOurScheme = (url: string) => url.startsWith(APP_SCHEME);
      expect(isOurScheme('novra-health://reset-password#access_token=...')).toBe(true);
      expect(isOurScheme('https://evil.com/reset-password#access_token=...')).toBe(false);
      expect(isOurScheme('exp://something')).toBe(false);
      logResult('Deep link: only novra-health:// scheme accepted', true);
    } catch (e) { logResult('Deep link: only novra-health:// scheme accepted', false, e); throw e; }
  });
});

