describe('login.tsx — password validation logic', () => {

  function validateSignupPassword(password: string): string | null {
    if (password.length < 12) return 'Password must be at least 12 characters.';
    if (!/[A-Z]/.test(password)) return 'Include at least one uppercase letter.';
    if (!/[0-9]/.test(password)) return 'Include at least one number.';
    return null;
  }

  test('valid password passes all checks', () => {
    try {
      expect(validateSignupPassword('SecurePass123!')).toBeNull();
      expect(validateSignupPassword('MyPassword1234')).toBeNull();
      logResult('Password validation: valid passwords pass', true);
    } catch (e) { logResult('Password validation: valid passwords pass', false, e); throw e; }
  });

  test('short password fails length check', () => {
    try {
      const err = validateSignupPassword('Short1A');
      expect(err).toMatch(/12 characters/);
      logResult('Password validation: < 12 chars rejected', true);
    } catch (e) { logResult('Password validation: < 12 chars rejected', false, e); throw e; }
  });

  test('no uppercase fails', () => {
    try {
      const err = validateSignupPassword('alllowercase123');
      expect(err).toMatch(/uppercase/i);
      logResult('Password validation: no uppercase → rejected', true);
    } catch (e) { logResult('Password validation: no uppercase → rejected', false, e); throw e; }
  });

  test('no number fails', () => {
    try {
      const err = validateSignupPassword('NoNumbersHereXYZ');
      expect(err).toMatch(/number/i);
      logResult('Password validation: no number → rejected', true);
    } catch (e) { logResult('Password validation: no number → rejected', false, e); throw e; }
  });
});

