// 10. LOGIC — workout.tsx calorie estimation
// ══════════════════════════════════════════════════════════════

describe('workout.tsx — MET-based calorie estimation', () => {

  function estimateCals(muscleGroup: string, weightKg: number, durationMin: number, completionRatio: number): number {
    const MET_BY_GROUP: Record<string, number> = {
      cardio: 8, chest: 5, back: 5, legs: 6, shoulders: 4, arms: 4, core: 5,
    };
    const met = MET_BY_GROUP[muscleGroup?.toLowerCase() ?? ''] ?? 5;
    return Math.round(met * weightKg * (durationMin / 60) * completionRatio);
  }

  test('full completion → correct calorie estimate', () => {
    try {
      const cals = estimateCals('chest', 80, 50, 1.0);
      // 5 * 80 * (50/60) * 1.0 = 5 * 80 * 0.833 = 333
      expect(cals).toBeCloseTo(333, 0);
      logResult('MET estimation: chest 80kg 50min 100% ≈ 333 kcal', true);
    } catch (e) { logResult('MET estimation: chest 80kg 50min 100% ≈ 333 kcal', false, e); throw e; }
  });

  test('0% completion → 0 calories', () => {
    try {
      expect(estimateCals('chest', 80, 50, 0)).toBe(0);
      logResult('MET estimation: 0% completion → 0 kcal', true);
    } catch (e) { logResult('MET estimation: 0% completion → 0 kcal', false, e); throw e; }
  });

  test('cardio has highest MET (8)', () => {
    try {
      const cardio = estimateCals('cardio', 70, 45, 1.0);
      const arms   = estimateCals('arms',   70, 45, 1.0);
      expect(cardio).toBeGreaterThan(arms);
      logResult('MET estimation: cardio > arms calorie burn', true);
    } catch (e) { logResult('MET estimation: cardio > arms calorie burn', false, e); throw e; }
  });

  test('unknown muscle group defaults to MET=5', () => {
    try {
      const unknown = estimateCals('mystery', 70, 60, 1.0); // 5 * 70 * 1 * 1 = 350
      const chest   = estimateCals('chest',   70, 60, 1.0); // 5 * 70 * 1 * 1 = 350
      expect(unknown).toBe(chest);
      logResult('MET estimation: unknown group defaults to 5', true);
    } catch (e) { logResult('MET estimation: unknown group defaults to 5', false, e); throw e; }
  });
});

